<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

  html, body {
    width: 100%; height: 100%;
    overflow: hidden;
    font-family: 'Segoe UI', Ubuntu, Cantarell, 'Helvetica Neue', sans-serif;
    background: #1a1a2e;
    color: #e0e0e0;
    user-select: none;
  }

  /* ── Desktop ── */
  #desktop {
    position: fixed;
    top: 0; left: 0; right: 0; bottom: 0;
    background: linear-gradient(135deg, #1a1a2e 0%, #16213e 40%, #0f3460 100%);
    display: flex;
    flex-direction: column;
    z-index: 0;
  }

  /* ── Top Bar ── */
  #topbar {
    height: 28px;
    background: #111;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 12px;
    font-size: 13px;
    color: #ccc;
    z-index: 100;
    flex-shrink: 0;
  }
  #topbar .left { display: flex; align-items: center; gap: 14px; }
  #topbar .center { font-weight: 600; color: #ddd; }
  #topbar .right { display: flex; align-items: center; gap: 10px; font-size: 12px; }

  /* ── Taskbar / Dock ── */
  #taskbar {
    position: fixed;
    bottom: 0; left: 0; right: 0;
    height: 52px;
    background: rgba(17, 17, 17, 0.92);
    backdrop-filter: blur(12px);
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    z-index: 200;
    border-top: 1px solid rgba(255,255,255,0.06);
  }
  .dock-btn {
    width: 42px; height: 42px;
    border-radius: 10px;
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.15s, transform 0.1s;
    position: relative;
  }
  .dock-btn:hover { background: rgba(255,255,255,0.12); transform: scale(1.08); }
  .dock-btn:active { transform: scale(0.95); }
  .dock-btn svg { width: 26px; height: 26px; }
  .dock-btn .dot {
    position: absolute; bottom: -2px; left: 50%; transform: translateX(-50%);
    width: 5px; height: 5px; border-radius: 50%;
    background: #e95420;
    opacity: 0;
    transition: opacity 0.2s;
  }
  .dock-btn.active .dot { opacity: 1; }

  /* ── Windows ── */
  .app-window {
    position: absolute;
    min-width: 360px;
    min-height: 240px;
    background: #2d2d2d;
    border-radius: 10px;
    box-shadow: 0 8px 40px rgba(0,0,0,0.55), 0 0 0 1px rgba(255,255,255,0.06);
    display: none;
    flex-direction: column;
    overflow: hidden;
    z-index: 50;
  }
  .app-window.visible { display: flex; }

  .win-titlebar {
    height: 38px;
    background: #1e1e1e;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 10px;
    cursor: grab;
    flex-shrink: 0;
    border-bottom: 1px solid #333;
  }
  .win-titlebar:active { cursor: grabbing; }
  .win-title { font-size: 13px; color: #aaa; font-weight: 500; }
  .win-controls { display: flex; gap: 6px; }
  .win-controls button {
    width: 14px; height: 14px; border-radius: 50%; border: none; cursor: pointer;
  }
  .win-close { background: #e95420; }
  .win-close:hover { background: #ff6b35; }
  .win-minimize { background: #f5c542; }
  .win-maximize { background: #44c94e; }

  .win-body {
    flex: 1;
    overflow: auto;
    display: flex;
    flex-direction: column;
  }

  /* ── Files App ── */
  #files-window { width: 720px; height: 480px; }
  #files-toolbar {
    display: flex; align-items: center; gap: 8px;
    padding: 6px 12px; background: #1e1e1e; border-bottom: 1px solid #333;
  }
  #files-up {
    background: #3a3a3a; color: #ccc; border: 1px solid #444;
    border-radius: 6px; padding: 4px 12px; cursor: pointer; font-size: 13px;
  }
  #files-up:hover { background: #4a4a4a; }
  #files-path {
    flex: 1; background: #111; border: 1px solid #444; border-radius: 6px;
    padding: 4px 12px; color: #ddd; font-size: 13px; font-family: monospace;
  }
  #files-list {
    flex: 1; padding: 12px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(90px, 1fr));
    gap: 8px;
    align-content: start;
    overflow-y: auto;
  }
  .fs-item {
    display: flex; flex-direction: column; align-items: center;
    padding: 10px 6px; border-radius: 8px; cursor: pointer;
    transition: background 0.12s;
  }
  .fs-item:hover { background: rgba(255,255,255,0.07); }
  .fs-item .icon { font-size: 36px; margin-bottom: 4px; }
  .fs-item .name { font-size: 12px; color: #ccc; text-align: center; word-break: break-word; }
  .fs-item.folder .icon { color: #e95420; }
  .fs-item.file .icon { color: #7eb8e0; }

  /* ── Notepad App ── */
  #notepad-window { width: 640px; height: 460px; }
  #notepad-toolbar {
    display: flex; align-items: center; gap: 6px;
    padding: 6px 12px; background: #1e1e1e; border-bottom: 1px solid #333;
  }
  #new-tab {
    background: #3a3a3a; color: #ccc; border: 1px solid #444;
    border-radius: 6px; padding: 4px 12px; cursor: pointer; font-size: 13px;
  }
  #new-tab:hover { background: #4a4a4a; }
  #tabs {
    display: flex; align-items: center; gap: 2px;
    padding: 0 8px; background: #1a1a1a; border-bottom: 1px solid #333;
    overflow-x: auto;
  }
  .tab {
    display: flex; align-items: center; gap: 6px;
    padding: 6px 14px; background: #2a2a2a; border-radius: 6px 6px 0 0;
    cursor: pointer; font-size: 12px; color: #999; white-space: nowrap;
    border: 1px solid transparent; border-bottom: none;
    transition: background 0.12s, color 0.12s;
  }
  .tab:hover { background: #333; color: #ccc; }
  .tab.active { background: #2d2d2d; color: #e0e0e0; border-color: #444; }
  .tab .tab-close {
    width: 14px; height: 14px; border-radius: 50%; border: none;
    background: transparent; color: #888; font-size: 11px; cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    line-height: 1;
  }
  .tab .tab-close:hover { background: #e95420; color: #fff; }
  #editor {
    flex: 1; background: #1e1e1e; color: #d4d4d4; border: none;
    padding: 14px; font-family: 'Cascadia Code', 'Fira Code', 'Consolas', monospace;
    font-size: 14px; line-height: 1.6; resize: none; outline: none;
    tab-size: 4;
  }
</style>
</head>
<body>

<div id="desktop">

  <!-- Top Bar -->
  <div id="topbar">
    <div class="left">
      <span style="font-weight:700;color:#e95420;">●</span>
      <span>Activities</span>
    </div>
    <div class="center" id="topbar-clock"></div>
    <div class="right">
      <span>🔊</span>
      <span>📶</span>
      <span>🔋</span>
      <span>⚙️</span>
    </div>
  </div>

  <!-- Taskbar / Dock -->
  <div id="taskbar">
    <button class="dock-btn" id="open-files" title="Files">
      <svg viewBox="0 0 24 24" fill="none" stroke="#e95420" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">
        <path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/>
      </svg>
      <span class="dot"></span>
    </button>
    <button class="dock-btn" id="open-notepad" title="Notepad">
      <svg viewBox="0 0 24 24" fill="none" stroke="#7eb8e0" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">
        <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/>
        <polyline points="14 2 14 8 20 8"/>
        <line x1="16" y1="13" x2="8" y2="13"/>
        <line x1="16" y1="17" x2="8" y2="17"/>
        <polyline points="10 9 9 9 8 9"/>
      </svg>
      <span class="dot"></span>
    </button>
  </div>

  <!-- Files Window -->
  <div class="app-window" id="files-window">
    <div class="win-titlebar" id="files-titlebar">
      <span class="win-title">Files</span>
      <div class="win-controls">
        <button class="win-minimize"></button>
        <button class="win-maximize"></button>
        <button class="win-close"></button>
      </div>
    </div>
    <div class="win-body">
      <div id="files-toolbar">
        <button id="files-up">⬆ Up</button>
        <div id="files-path">/</div>
      </div>
      <div id="files-list"></div>
    </div>
  </div>

  <!-- Notepad Window -->
  <div class="app-window" id="notepad-window">
    <div class="win-titlebar" id="notepad-titlebar">
      <span class="win-title">Notepad</span>
      <div class="win-controls">
        <button class="win-minimize"></button>
        <button class="win-maximize"></button>
        <button class="win-close"></button>
      </div>
    </div>
    <div class="win-body">
      <div id="notepad-toolbar">
        <button id="new-tab">+ New Tab</button>
      </div>
      <div id="tabs"></div>
      <textarea id="editor" spellcheck="false"></textarea>
    </div>
  </div>

</div>

<script>
(function() {
  "use strict";

  /* ── Clock ── */
  function updateClock() {
    const d = new Date();
    const opts = { weekday:'short', month:'short', day:'numeric', hour:'2-digit', minute:'2-digit' };
    document.getElementById('topbar-clock').textContent = d.toLocaleDateString('en-US', opts);
  }
  updateClock();
  setInterval(updateClock, 30000);

  /* ── Dock active indicators ── */
  const filesBtn = document.getElementById('open-files');
  const notepadBtn = document.getElementById('open-notepad');
  const filesWin = document.getElementById('files-window');
  const notepadWin = document.getElementById('notepad-window');

  function toggleWindow(btn, win) {
    if (win.classList.contains('visible')) {
      win.classList.remove('visible');
      btn.classList.remove('active');
    } else {
      win.classList.add('visible');
      btn.classList.add('active');
    }
  }

  document.getElementById('open-files').addEventListener('click', function() {
    toggleWindow(filesBtn, filesWin);
  });
  document.getElementById('open-notepad').addEventListener('click', function() {
    toggleWindow(notepadBtn, notepadWin);
  });

  /* ── Draggable Windows ── */
  function makeDraggable(win, titlebar) {
    let startX, startY, origX, origY, dragging = false;

    titlebar.addEventListener('mousedown', function(e) {
      if (e.target.classList.contains('win-close') || e.target.classList.contains('win-minimize') || e.target.classList.contains('win-maximize')) return;
      dragging = true;
      startX = e.clientX;
      startY = e.clientY;
      origX = win.offsetLeft;
      origY = win.offsetTop;
      win.style.zIndex = ++zCounter;
      document.addEventListener('mousemove', onMove);
      document.addEventListener('mouseup', onUp);
      e.preventDefault();
    });

    function onMove(e) {
      if (!dragging) return;
      const dx = e.clientX - startX;
      const dy = e.clientY - startY;
      win.style.left = (origX + dx) + 'px';
      win.style.top = (origY + dy) + 'px';
    }
    function onUp() {
      dragging = false;
      document.removeEventListener('mousemove', onMove);
      document.removeEventListener('mouseup', onUp);
    }
  }

  let zCounter = 60;
  makeDraggable(filesWin, document.getElementById('files-titlebar'));
  makeDraggable(notepadWin, document.getElementById('notepad-titlebar'));

  /* ── Close buttons ── */
  document.querySelectorAll('.win-close').forEach(function(btn) {
    btn.addEventListener('click', function() {
      const win = btn.closest('.app-window');
      win.classList.remove('visible');
      if (win === filesWin) filesBtn.classList.remove('active');
      if (win === notepadWin) notepadBtn.classList.remove('active');
    });
  });

  /* ── Files App ── */
  const fileSystem = {
    '/': ['bin', 'etc', 'home', 'usr', 'var'],
    '/bin': ['bash', 'ls', 'cat', 'cp', 'mv', 'rm'],
    '/etc': ['passwd', 'hostname', 'fstab', 'resolv.conf'],
    '/home': ['user'],
    '/home/user': ['Documents', 'Downloads', 'Pictures', 'Desktop', '.bashrc', '.profile'],
    '/home/user/Documents': ['readme.txt', 'notes.md', 'report.pdf'],
    '/home/user/Downloads': ['setup.deb', 'image.png', 'archive.tar.gz'],
    '/home/user/Pictures': ['wallpaper.jpg', 'screenshot.png', 'photo.jpg'],
    '/home/user/Desktop': ['shortcut.desktop'],
    '/usr': ['bin', 'lib', 'share', 'local'],
    '/usr/bin': ['python3', 'node', 'git', 'vim'],
    '/usr/lib': ['libc.so', 'libssl.so'],
    '/usr/share': ['doc', 'man', 'locale'],
    '/var': ['log', 'cache', 'tmp', 'www'],
    '/var/log': ['syslog', 'auth.log', 'kern.log'],
    '/var/cache': ['apt', 'pip'],
    '/var/tmp': [],
    '/var/www': ['index.html', 'config.php']
  };

  let currentPath = '/';

  function renderFiles() {
    const list = document.getElementById('files-list');
    const pathEl = document.getElementById('files-path');
    pathEl.textContent = currentPath;
    list.innerHTML = '';

    const entries = fileSystem[currentPath] || [];
    entries.forEach(function(name) {
      const item = document.createElement('div');
      const fullPath = currentPath === '/' ? '/' + name : currentPath + '/' + name;
      const isFolder = fileSystem[fullPath] !== undefined;
      item.className = 'fs-item ' + (isFolder ? 'folder' : 'file');
      item.innerHTML = '<span class="icon">' + (isFolder ? '📁' : '📄') + '</span><span class="name">' + name + '</span>';

      if (isFolder) {
        item.addEventListener('dblclick', function() {
          currentPath = fullPath;
          renderFiles();
        });
      }
      item.addEventListener('click', function() {
        // single click highlight
        list.querySelectorAll('.fs-item').forEach(function(el) { el.style.background = ''; });
        item.style.background = 'rgba(233,84,32,0.15)';
      });

      list.appendChild(item);
    });
  }

  document.getElementById('files-up').addEventListener('click', function() {
    if (currentPath === '/') return;
    const parts = currentPath.split('/').filter(Boolean);
    parts.pop();
    currentPath = '/' + parts.join('/');
    if (currentPath === '') currentPath = '/';
    renderFiles();
  });

  renderFiles();

  /* ── Notepad App ── */
  const STORAGE_KEY = 'ubuntu-notepad-tabs';

  function loadTabs() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) return JSON.parse(raw);
    } catch(e) {}
    return [];
  }

  function saveTabs() {
    const tabs = getTabs();
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tabs));
  }

  let tabs = loadTabs();
  let activeTabIndex = 0;

  function getTabs() {
    const tabEls = document.querySelectorAll('#tabs .tab');
    const result = [];
    tabEls.forEach(function(el) {
      result.push({
        name: el.getAttribute('data-name'),
        content: el.getAttribute('data-content') || ''
      });
    });
    return result;
  }

  function renderTabs() {
    const tabsEl = document.getElementById('tabs');
    tabsEl.innerHTML = '';
    tabs.forEach(function(t, i) {
      const tab = document.createElement('div');
      tab.className = 'tab' + (i === activeTabIndex ? ' active' : '');
      tab.setAttribute('data-name', t.name);
      tab.setAttribute('data-content', t.content);
      tab.innerHTML = '<span class="tab-label">' + escapeHtml(t.name) + '</span><button class="tab-close" title="Close">✕</button>';

      tab.querySelector('.tab-label').addEventListener('click', function() {
        activeTabIndex = i;
        renderTabs();
        document.getElementById('editor').value = t.content;
      });

      tab.querySelector('.tab-close').addEventListener('click', function(e) {
        e.stopPropagation();
        tabs.splice(i, 1);
        if (activeTabIndex >= tabs.length) activeTabIndex = Math.max(0, tabs.length - 1);
        saveTabs();
        renderTabs();
        if (tabs.length > 0) {
          document.getElementById('editor').value = tabs[activeTabIndex].content;
        } else {
          document.getElementById('editor').value = '';
        }
      });

      tabsEl.appendChild(tab);
    });
  }

  function escapeHtml(str) {
    return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }

  function addTab(name, content) {
    tabs.push({ name: name || 'Untitled', content: content || '' });
    activeTabIndex = tabs.length - 1;
    saveTabs();
    renderTabs();
    document.getElementById('editor').value = tabs[activeTabIndex].content;
  }

  document.getElementById('new-tab').addEventListener('click', function() {
    addTab('Untitled ' + (tabs.length + 1), '');
  });

  document.getElementById('editor').addEventListener('input', function() {
    if (tabs.length > 0 && activeTabIndex >= 0 && activeTabIndex < tabs.length) {
      tabs[activeTabIndex].content = this.value;
      saveTabs();
    }
  });

  // Restore from storage
  if (tabs.length === 0) {
    tabs.push({ name: 'Welcome', content: 'Welcome to Notepad!\n\nThis is a tabbed text editor.\n\n• Click "+ New Tab" to create a new tab\n• Click a tab to switch to it\n• All content is saved automatically\n• Close and reopen the window — your tabs persist!' });
    activeTabIndex = 0;
    saveTabs();
  }

  renderTabs();
  if (tabs.length > 0) {
    document.getElementById('editor').value = tabs[activeTabIndex].content;
  }

})();
</script>
</body>
</html>
